const results = $json.results || [];
const sorted = results
  .map(r => ({ name: r.name, address: r.vicinity, rating: r.rating || 0, place_id: r.place_id }))
  .sort((a,b) => b.rating - a.rating)
  .slice(0,3);
return [{ spots: sorted }];

