parameters.functionCode:
const spots = $json.spots || [];
if (!spots.length) return { mapsUrl: 'No spots found', mrkdwn: true };

const formatSpot = (s) => {
  const name = s.name || '';
  const address = s.address || '';

  if (!address.includes('中野区') && !address.includes('杉並区') && !address.includes('東京都')) {
    return `東京都中野区 ${name}`;
  }
  return `${name} ${address}`;
};

const waypoints = spots.slice(0, -1).map(s => formatSpot(s)).join('|');
const origin = '中野駅 東京都中野区';
const destination = formatSpot(spots[spots.length - 1]);

const url = encodeURI(
  `https://www.google.com/maps/dir/?api=1&origin=${origin}&destination=${destination}&travelmode=walking&waypoints=${waypoints}`
);

// 👇 text → mapsUrl に変更！
return {
  mapsUrl: `🗺️ <${url}|View the route on Google Maps>`,
  mrkdwn: true
};

